// Package terraform_dabs_map provides a precomputed bidirectional mapping between
// DABs resource fields and Terraform resource fields, generated by generate_test.go.
package terraform_dabs_map

import "github.com/databricks/cli/libs/structs/structpath"

// FieldSet is a nested set of field path segments. Each key is a single field name;
// an empty child FieldSet marks a leaf (the full path from root is present in the set).
type FieldSet map[string]FieldSet

// Contains reports whether path is in the FieldSet.
// Walking the path segment by segment, it returns true when a leaf node is
// reached (covering all sub-paths) or when an exact match is found.
// Array indices are ignored; "*" matches any key at that level.
func (fs FieldSet) Contains(path *structpath.PathNode) bool {
	current := fs
	for _, n := range path.AsSlice() {
		key, ok := n.StringKey()
		if !ok {
			continue // skip array indices and key=value nodes
		}
		child, found := current[key]
		if !found {
			child, found = current["*"]
		}
		if !found {
			return false
		}
		if len(child) == 0 {
			return true // leaf: this path and all sub-paths are covered
		}
		current = child
	}
	return false
}

// RenameNode is one node in a bidirectional rename tree. NewName is the counterpart segment
// name in the other naming scheme when it differs from the key; Children holds renames for
// deeper paths. Both may be set when the segment itself is renamed and sub-fields are renamed too.
// Unwrap marks a structural wrapper in TerraformToDABsFieldMap: the TF segment has no DABs
// equivalent and is consumed without emitting a segment. Unwrap and NewName are mutually exclusive.
type RenameNode struct {
	NewName  string
	Unwrap   bool
	Children RenameTree
}

// RenameTree maps single TF field name segments to their rename nodes.
type RenameTree map[string]RenameNode
